import os
import json
import uuid
import hashlib

def generate_document_code(relative_path):
 # Create a stable code based on the path
 hash_object = hashlib.md5(relative_path.encode())
 return f"DOC-{hash_object.hexdigest()[:12].upper()}"

def generate_chunk_uid(doc_code, chunk_index):
 return f"{doc_code}-CHK-{chunk_index}"

def chunk_text(text, max_tokens=1000):
 # A simple paragraph-based chunker for Markdown/text files
 paragraphs = text.split('\n\n')
 chunks = []
 current_chunk = ""
 for para in paragraphs:
 if len(current_chunk) + len(para) > max_tokens * 4: # approx 4 chars per token
 if current_chunk.strip():
 chunks.append(current_chunk.strip())
 current_chunk = para + "\n\n"
 else:
 current_chunk += para + "\n\n"
 if current_chunk.strip():
 chunks.append(current_chunk.strip())
 # fallback if empty
 if not chunks and text.strip():
 chunks.append(text.strip())
 return chunks

def extract_documents(root_dir):
 valid_extensions = ['.md', '.txt', '.json', '.csv', '.tsv']

 document_sources = []
 document_chunks = []

 for dirpath, _, filenames in os.walk(root_dir):
 for filename in filenames:
 if any(filename.endswith(ext) for ext in valid_extensions):
 # Skip the script itself or the output file
 if filename in ['extract_script.py', 'cellcycle_extracted_knowledge.json']:
 continue

 file_path = os.path.join(dirpath, filename)
 relative_path = os.path.relpath(file_path, root_dir)

 try:
 with open(file_path, 'r', encoding='utf-8') as f:
 content = f.read()
 except Exception as e:
 print(f"Failed to read {file_path}: {e}")
 continue

 # Document Source
 doc_code = generate_document_code(relative_path)
 source_type = filename.split('.')[-1]

